.comment {
  border: 1px solid #eee;
  padding: 15px;
  margin-bottom: 15px;
  border-radius: 8px;
}

.comment h3 {
  margin-bottom: 5px;
  font-size: 16px;
}

.comment small {
  color: #666;
}

