import type { Metadata } from 'next';
import { notFound } from 'next/navigation';
import { BackButton } from '@/components/BackButton';
import type { Comment, Post } from '@/app/types';

interface BlogPostPageProps {
  params: Promise<{ id: string }>;
}

export async function generateStaticParams(): Promise<Array<{ id: string }>> {
  const response = await fetch('https://jsonplaceholder.typicode.com/posts');

  if (!response.ok) {
    return [];
  }

  const posts: Post[] = await response.json();

  return posts.slice(0, 10).map((post) => ({
    id: post.id.toString(),
  }));
}

async function getPostData(id: string): Promise<{ post: Post; comments: Comment[] } | null> {
  const [postResponse, commentsResponse] = await Promise.all([
    fetch(`https://jsonplaceholder.typicode.com/posts/${id}`, {
      next: { revalidate: 300 },
    }),
    fetch(`https://jsonplaceholder.typicode.com/posts/${id}/comments`, {
      next: { revalidate: 300 },
    }),
  ]);

  if (!postResponse.ok || !commentsResponse.ok) {
    return null;
  }

  const post: Post = await postResponse.json();
  const comments: Comment[] = await commentsResponse.json();

  if (!post.id) {
    return null;
  }

  return { post, comments };
}

export async function generateMetadata({ params }: BlogPostPageProps): Promise<Metadata> {
  const { id } = await params;
  const data = await getPostData(id);

  if (!data) {
    return {
      title: 'Post Not Found',
      description: 'The requested blog post could not be found.',
    };
  }

  return {
    title: data.post.title,
    description: data.post.body?.substring(0, 160) ?? 'Blog post details',
    openGraph: {
      title: data.post.title,
      description: data.post.body?.substring(0, 160) ?? 'Blog post details',
    },
  };
}

export default async function BlogPostPage({ params }: BlogPostPageProps) {
  const { id } = await params;
  const data = await getPostData(id);

  if (!data) {
    notFound();
  }

  const { post, comments } = data;

  return (
    <article>
      <BackButton />

      <h1>{post.title}</h1>
      <p>{post.body}</p>

      <h2>Comments ({comments.length})</h2>
      <div className="comments">
        {comments.map((comment) => (
          <div key={comment.id} className="comment">
            <h3>{comment.name}</h3>
            <p>{comment.body}</p>
            <small>By: {comment.email}</small>
          </div>
        ))}
      </div>
    </article>
  );
}
EOF

